import{_ as e,c as t,a2 as r,o}from"./chunks/framework.DPuwY6B9.js";const u=JSON.parse('{"title":"角色组","description":"","frontmatter":{},"headers":[],"relativePath":"guide/group.md","filePath":"zh/guide/group.md","lastUpdated":1732501360000}'),i={name:"guide/group.md"};function d(n,a,p,l,s,c){return o(),t("div",null,a[0]||(a[0]=[r('<h1 id="角色组" tabindex="-1">角色组 <a class="header-anchor" href="#角色组" aria-label="Permalink to &quot;角色组&quot;">​</a></h1><p>角色组是兰空图床最重要的组成部分，所有用户(包括管理员)都受角色组控制，我们可以通过角色组控制用户的可使用的储存、发件驱动、支付方式、上传限制等。</p><h2 id="基础" tabindex="-1">基础 <a class="header-anchor" href="#基础" aria-label="Permalink to &quot;基础&quot;">​</a></h2><p>系统中可以创建多个不同的角色组，默认组或游客组同时只能存在一个，新注册用户将默认归属为默认角色组，未登录用户则使用游客组。</p><p>每个组可以分别设置多个短信驱动、邮件驱动、支付驱动。其中短信驱动与邮件驱动，程序支持故障转移功能，按顺序发件如果出现错误，则自动切换到下一个可用驱动发件。</p><h2 id="允许上传的文件类型" tabindex="-1">允许上传的文件类型 <a class="header-anchor" href="#允许上传的文件类型" aria-label="Permalink to &quot;允许上传的文件类型&quot;">​</a></h2><p>系统中的图片上传功能，包括游客，都是通过角色组控制上传的频率、格式，而可上传的图片格式由 imagick 拓展控制。</p><p>有关 ImageMagick 拓展的详细说明请查阅 <a href="/guide/requirement#imagemagick">环境要求</a> 章节。</p><h2 id="储存" tabindex="-1">储存 <a class="header-anchor" href="#储存" aria-label="Permalink to &quot;储存&quot;">​</a></h2><p>每个角色组可以关联多个储存，属于该角色组的用户将拥有已关联的所有储存，在用户中心可以切换不同的储存上传图片。按照惯例，每个角色组应该始终最少关联一个储存。</p>',10)]))}const m=e(i,[["render",d]]);export{u as __pageData,m as default};
